class DynamicMessageRouter:
    def __init__(self) -> None:
        self._handlers: Dict[str, Callable[[BaseEvent], None]] = {}

    def register(self, event_type: str, handler: Callable[[BaseEvent], None]) -> None:
        self._handlers[event_type] = handler

    def dispatch(self, event: BaseEvent) -> None:
        handler = self._handlers.get(event.event_type)
        if not handler:
            raise HandlerNotFoundError(f"no handler registered for event_type={event.event_type}")
        handler(event)


